import { _decorator, Component, director, Node, Label, Button, ScrollView, Prefab, instantiate } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('PVPScene')
export class PVPScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Button)
    matchBtn: Button = null;
    
    @property(Button)
    rankBtn: Button = null;
    
    @property(Label)
    currentRankLabel: Label = null;
    
    @property(Label)
    currentPointsLabel: Label = null;
    
    @property(Label)
    seasonTimeLabel: Label = null;
    
    @property(ScrollView)
    rankListScrollView: ScrollView = null;
    
    @property(Node)
    rankItemPrefab: Node = null;
    
    @property(Node)
    matchingPanel: Node = null;
    
    @property(Label)
    matchTimeLabel: Label = null;
    
    // 段位数据
    private ranks = [
        { name: '青铜', minPoints: 0, maxPoints: 99, icon: '🥉' },
        { name: '白银', minPoints: 100, maxPoints: 299, icon: '🥈' },
        { name: '黄金', minPoints: 300, maxPoints: 599, icon: '🥇' },
        { name: '铂金', minPoints: 600, maxPoints: 999, icon: '💎' },
        { name: '钻石', minPoints: 1000, maxPoints: 1499, icon: '💎💎' },
        { name: '星耀', minPoints: 1500, maxPoints: 2099, icon: '⭐' },
        { name: '封神', minPoints: 2100, maxPoints: 99999, icon: '👑' }
    ];
    
    // 排行榜数据
    private topPlayers = [
        { rank: 1, name: '财神本尊', points: 3500, tier: '封神' },
        { rank: 2, name: '不败神话', points: 3200, tier: '封神' },
        { rank: 3, name: '战神无双', points: 2980, tier: '封神' },
        { rank: 4, name: '王者归来', points: 2750, tier: '星耀' },
        { rank: 5, name: '无敌是多么寂寞', points: 2600, tier: '星耀' }
    ];
    
    private playerPoints = 150;
    private isMatching = false;
    private matchTime = 0;
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.matchBtn.node.on(Button.EventType.CLICK, this.onMatch, this);
        this.rankBtn.node.on(Button.EventType.CLICK, this.onShowRank, this);
    }
    
    start() {
        this.updatePlayerInfo();
        this.updateRankList();
        this.matchingPanel.active = false;
    }
    
    updatePlayerInfo() {
        const currentTier = this.getTierByPoints(this.playerPoints);
        this.currentRankLabel.string = `当前段位: ${currentTier.icon} ${currentTier.name}`;
        this.currentPointsLabel.string = `积分: ${this.playerPoints}`;
        
        // 赛季剩余时间（模拟）
        this.seasonTimeLabel.string = '赛季剩余: 45天';
    }
    
    getTierByPoints(points: number) {
        for (const tier of this.ranks) {
            if (points >= tier.minPoints && points <= tier.maxPoints) {
                return tier;
            }
        }
        return this.ranks[0];
    }
    
    updateRankList() {
        const content = this.rankListScrollView.content;
        content.removeAllChildren();
        
        for (const player of this.topPlayers) {
            const node = instantiate(this.rankItemPrefab);
            
            node.getChildByName('RankLabel').getComponent(Label).string = `#${player.rank}`;
            node.getChildByName('NameLabel').getComponent(Label).string = player.name;
            node.getChildByName('PointsLabel').getComponent(Label).string = `${player.points}分`;
            node.getChildByName('TierLabel').getComponent(Label).string = player.tier;
            
            content.addChild(node);
        }
    }
    
    onMatch() {
        if (this.isMatching) return;
        
        this.isMatching = true;
        this.matchTime = 0;
        this.matchingPanel.active = true;
        this.matchBtn.interactable = false;
        
        this.schedule(this.updateMatchTime, 1);
        
        // 模拟匹配成功（3-10秒）
        const matchDuration = 3 + Math.random() * 7;
        this.scheduleOnce(() => {
            this.onMatchFound();
        }, matchDuration);
    }
    
    updateMatchTime() {
        this.matchTime++;
        this.matchTimeLabel.string = `匹配中... ${this.matchTime}秒`;
    }
    
    onMatchFound() {
        this.unschedule(this.updateMatchTime);
        this.isMatching = false;
        this.matchingPanel.active = false;
        this.matchBtn.interactable = true;
        
        // 进入战斗
        console.log('匹配成功！进入战斗');
        director.loadScene('BattleScene');
        
        // 战斗结束后结算积分（模拟）
        this.scheduleOnce(() => {
            const win = Math.random() > 0.5;
            if (win) {
                this.playerPoints += 20;
                console.log('战斗胜利！+20分');
            } else {
                this.playerPoints = Math.max(0, this.playerPoints - 15);
                console.log('战斗失败！-15分');
            }
            this.updatePlayerInfo();
        }, 2);
    }
    
    onShowRank() {
        // 显示完整排行榜
        console.log('显示完整排行榜');
    }
    
    onBack() {
        if (this.isMatching) {
            this.unschedule(this.updateMatchTime);
            this.unschedule(this.onMatchFound);
        }
        director.loadScene('MainScene');
    }
    
    onDestroy() {
        this.unscheduleAllCallbacks();
    }
}
